import type { CareerQuestion } from "./rrt-questions";

export const himQuestionsBatch8: CareerQuestion[] = [
  { id: "him-653", stem: "What is the purpose of the ICD-10-CM Official Guidelines for Coding and Reporting?", options: ["To provide rules and instructions for proper code selection and sequencing that complement the conventions and instructions in the classification", "To replace physician documentation", "To establish reimbursement rates for all payers", "To define clinical treatment protocols"], correctIndex: 0, rationale: "The Official Guidelines accompany the ICD-10-CM classification and provide coding conventions, general guidelines, and chapter-specific guidelines essential for accurate code assignment and sequencing.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-654", stem: "According to ICD-10-CM guidelines, the term 'and' in a code title means:", options: ["And/or", "Only 'and' (both conditions must be present)", "Neither condition", "The first condition only"], correctIndex: 0, rationale: "In ICD-10-CM, the word 'and' should be interpreted as meaning 'and/or.' For example, cases of 'tuberculosis of bones and joints' should be classified under that rubric whether tuberculosis involves bones, joints, or both.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-655", stem: "What does an Excludes1 note in ICD-10-CM indicate?", options: ["The two conditions cannot occur together and both codes cannot be assigned simultaneously", "The condition is included in the code", "The excluded condition may be coded together if documented", "The code requires an additional character"], correctIndex: 0, rationale: "An Excludes1 note is a 'pure' excludes meaning the two conditions are mutually exclusive and cannot be reported together. The excluded condition cannot reasonably occur with the code it is excluded from.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Excludes Notes" },
  { id: "him-656", stem: "An Excludes2 note in ICD-10-CM means:", options: ["The excluded condition is not part of the condition represented by the code, but a patient may have both conditions and both codes may be assigned together", "The two conditions cannot coexist", "The code is invalid and should never be used", "Only one of the two conditions can be coded per encounter"], correctIndex: 0, rationale: "An Excludes2 note indicates the excluded condition is not inherently part of the coded condition, but when both conditions are documented, both codes can be assigned. This differs from Excludes1 where codes are mutually exclusive.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Excludes Notes" },
  { id: "him-657", stem: "A combination code in ICD-10-CM is:", options: ["A single code that classifies two diagnoses, a diagnosis with a secondary process, or a diagnosis with an associated complication", "Two codes always required to capture a condition", "A code used only in outpatient settings", "A code with exactly three characters"], correctIndex: 0, rationale: "Combination codes are single codes that classify two diagnoses, or a diagnosis with an associated secondary process (manifestation) or complication. When a combination code fully describes the conditions, no additional codes are needed.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Combination Codes" },
  { id: "him-658", stem: "When a combination code exists that accurately identifies a condition and its common manifestation, the coder should:", options: ["Assign only the combination code", "Assign separate codes for each condition", "Use the manifestation code as the principal diagnosis", "Report only the manifestation code"], correctIndex: 0, rationale: "Per ICD-10-CM guidelines, when a combination code fully captures the diagnostic conditions or a diagnosis with a common symptom/manifestation, only the combination code should be assigned. Additional codes should not be used.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Combination Codes" },
  { id: "him-659", stem: "In ICD-10-CM, a 7th character extension of 'A' indicates:", options: ["Initial encounter — active phase of treatment", "Subsequent encounter", "Sequela", "Adverse effect"], correctIndex: 0, rationale: "The 7th character 'A' designates initial encounter, meaning the patient is receiving active treatment for the condition. This applies to the entire course of active treatment, not just the first visit.", difficulty: 1, category: "ICD-10-CM Coding", topic: "7th Character Extensions" },
  { id: "him-660", stem: "The 7th character 'D' for subsequent encounter in ICD-10-CM is used when:", options: ["The patient is receiving routine care during the healing or recovery phase after active treatment", "The patient is being seen for the first time", "The condition has caused a late effect", "The condition is undiagnosed"], correctIndex: 0, rationale: "The 7th character 'D' designates subsequent encounter for routine care during the healing phase, such as cast changes, removal of fixation devices, medication adjustments, or other aftercare and follow-up visits.", difficulty: 1, category: "ICD-10-CM Coding", topic: "7th Character Extensions" },
  { id: "him-661", stem: "The 7th character 'S' for sequela in ICD-10-CM is used for:", options: ["Complications or conditions that arise as a direct result of a previously healed condition", "Initial acute treatment", "Routine healing phase care", "Surgical procedures only"], correctIndex: 0, rationale: "The 7th character 'S' identifies sequela — residual effects (late effects) that occur after the acute phase of an illness or injury has terminated. The sequela is sequenced first, followed by the cause code with 7th character 'S'.", difficulty: 2, category: "ICD-10-CM Coding", topic: "7th Character Extensions" },
  { id: "him-662", stem: "When the 7th character is required but the code has fewer than 7 characters, the coder should:", options: ["Use the placeholder character 'X' to fill empty positions", "Leave the positions blank", "Add zeros to fill the positions", "Shorten the code to 3 characters"], correctIndex: 0, rationale: "ICD-10-CM uses the placeholder character 'X' to fill empty character positions when a 7th character is required but the code contains fewer than 6 characters. The X has no meaning and holds the position only.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-663", stem: "According to ICD-10-CM Chapter 1 guidelines, when a patient is admitted for treatment of an HIV-related condition, the principal diagnosis should be:", options: ["B20, Human immunodeficiency virus [HIV] disease", "The HIV-related condition", "Z21, Asymptomatic HIV infection status", "The reason for the encounter"], correctIndex: 0, rationale: "When a patient is admitted for an HIV-related condition, B20 (Human immunodeficiency virus [HIV] disease) is sequenced as the principal diagnosis, followed by additional codes for all reported HIV-related conditions.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 1 Guidelines" },
  { id: "him-664", stem: "Code Z21 (Asymptomatic human immunodeficiency virus infection status) is used when:", options: ["The patient is HIV positive but has never had an HIV-related illness and is not currently ill from HIV", "The patient has AIDS", "The patient has an active opportunistic infection", "The patient's HIV test result is inconclusive"], correctIndex: 0, rationale: "Z21 is assigned for patients who test positive for HIV but have no symptoms and have never been diagnosed with an HIV-related illness. Once any HIV-related illness develops, only B20 should be used.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 1 Guidelines" },
  { id: "him-665", stem: "For sepsis coding in ICD-10-CM, the underlying systemic infection code should be:", options: ["Sequenced first, followed by a code for the specific organism if applicable", "Sequenced after the organ dysfunction code", "Reported as a secondary diagnosis only", "Never coded without a positive blood culture"], correctIndex: 0, rationale: "Per ICD-10-CM guidelines, the code for the underlying systemic infection is sequenced first. If the specific organism is not identified, code A41.9 (Sepsis, unspecified organism) should be assigned.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 1 Guidelines" },
  { id: "him-666", stem: "When severe sepsis is documented, the coder must assign:", options: ["A minimum of two codes: a code for the underlying systemic infection and a code from subcategory R65.2 (Severe sepsis)", "Only the sepsis code", "Only the organ dysfunction code", "A single combination code"], correctIndex: 0, rationale: "Severe sepsis requires at minimum a code for the underlying systemic infection followed by R65.2- (Severe sepsis). Additional codes for associated acute organ dysfunction should also be assigned.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 1 Guidelines" },
  { id: "him-667", stem: "According to ICD-10-CM guidelines, MRSA colonization is coded as:", options: ["Z22.322, Carrier or suspected carrier of methicillin resistant Staphylococcus aureus", "A49.02, MRSA infection, unspecified site", "B95.62, MRSA as the cause of diseases classified elsewhere", "Z16.11, Resistance to penicillins"], correctIndex: 0, rationale: "MRSA colonization (carrier state) without active infection is coded Z22.322. This differs from active MRSA infection which uses infection-specific codes plus B95.62 for the causal organism.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 1 Guidelines" },
  { id: "him-668", stem: "In ICD-10-CM Chapter 2 (Neoplasms), the Table of Neoplasms is used to:", options: ["Locate the correct code based on the anatomical site and behavior (malignant primary, secondary, in situ, benign, uncertain, unspecified) of the neoplasm", "Determine chemotherapy protocols", "Identify tumor staging", "Calculate survival rates"], correctIndex: 0, rationale: "The Table of Neoplasms in the Alphabetic Index lists codes by anatomical site across six columns representing neoplasm behavior: malignant primary, malignant secondary, carcinoma in situ, benign, uncertain behavior, and unspecified behavior.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 2 Guidelines" },
  { id: "him-669", stem: "When a patient is admitted for chemotherapy and the malignancy is still present, the principal diagnosis is:", options: ["Z51.11, Encounter for antineoplastic chemotherapy", "The malignancy code", "The adverse effect of chemotherapy", "The symptom prompting treatment"], correctIndex: 0, rationale: "When the encounter is primarily for chemotherapy, code Z51.11 is sequenced as the principal diagnosis. The malignancy code is assigned as an additional diagnosis.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 2 Guidelines" },
  { id: "him-670", stem: "A patient with a history of breast cancer who is currently cancer-free should be coded with:", options: ["Z85.3, Personal history of malignant neoplasm of breast", "C50.-, Malignant neoplasm of breast", "D05.-, Carcinoma in situ of breast", "Z80.3, Family history of malignant neoplasm of breast"], correctIndex: 0, rationale: "When a primary malignancy has been excised or eradicated and there is no evidence of current disease, a personal history code (Z85 category) should be assigned rather than the active neoplasm code.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 2 Guidelines" },
  { id: "him-671", stem: "Anemia associated with malignancy is coded by assigning:", options: ["The malignancy code first, followed by D63.0 (Anemia in neoplastic disease)", "Only the anemia code", "D63.0 as the principal diagnosis", "The malignancy code only"], correctIndex: 0, rationale: "Anemia associated with malignancy is coded with the neoplasm code sequenced first, followed by D63.0. When the encounter is primarily for treatment of the anemia, the anemia code may be sequenced first per guidelines.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 2 Guidelines" },
  { id: "him-672", stem: "In ICD-10-CM Chapter 3, when anemia is documented as associated with chemotherapy, the coder assigns:", options: ["First the adverse effect code (T45.1X5-), then D64.81 (Anemia due to antineoplastic chemotherapy), then the neoplasm code", "Only D64.81", "Only the neoplasm code", "Only the adverse effect code"], correctIndex: 0, rationale: "Anemia due to antineoplastic chemotherapy requires sequencing the adverse effect code T45.1X5- first, followed by D64.81, and then the neoplasm code. This differs from anemia associated with the malignancy itself.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Chapter 3 Guidelines" },
  { id: "him-673", stem: "ICD-10-CM Chapter 4 (Endocrine, Nutritional and Metabolic Diseases) guidelines for diabetes require:", options: ["As many codes as necessary from categories E08-E13 to describe all associated conditions the patient has", "Only one diabetes code per encounter", "A single code that captures all complications", "Separate codes only for Type 1 diabetes"], correctIndex: 0, rationale: "Diabetes codes in ICD-10-CM are combination codes. The coder should assign as many codes from categories E08-E13 as needed to identify all associated conditions. The diabetes codes are based on type and complication.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 4 Guidelines" },
  { id: "him-674", stem: "If the type of diabetes is not documented in the medical record, the default code is:", options: ["E11.- (Type 2 diabetes mellitus)", "E10.- (Type 1 diabetes mellitus)", "E13.- (Other specified diabetes mellitus)", "E09.- (Drug or chemical induced diabetes mellitus)"], correctIndex: 0, rationale: "Per ICD-10-CM guidelines, if the type of diabetes is not documented, the default is Type 2 diabetes (E11.-). Coders should not assume Type 1 unless explicitly documented by the provider.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 4 Guidelines" },
  { id: "him-675", stem: "A patient with Type 2 diabetes with diabetic chronic kidney disease stage 3 requires:", options: ["E11.22 (Type 2 diabetes with diabetic CKD) and N18.3 (CKD stage 3)", "Only E11.22", "Only N18.3", "E11.9 and N18.3"], correctIndex: 0, rationale: "Diabetes with CKD requires the combination code from E11.22 (Type 2 DM with diabetic CKD) plus the additional code N18.3 to identify the specific stage of CKD. Both codes are necessary for complete reporting.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 4 Guidelines" },
  { id: "him-676", stem: "According to Chapter 5 (Mental, Behavioral and Neurodevelopmental Disorders) guidelines, pain disorders with related psychological factors are coded with:", options: ["F45.41 (Pain disorder exclusively related to psychological factors) and a code from G89.- if applicable", "Only the pain code from G89", "Only the psychological disorder code", "No specific guidelines exist for this scenario"], correctIndex: 0, rationale: "When pain is exclusively related to psychological factors, F45.41 is assigned. A code from G89.- should also be assigned if there is documentation of acute or chronic pain, or neoplasm-related pain.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Chapter 5 Guidelines" },
  { id: "him-677", stem: "For alcohol dependence with withdrawal, the ICD-10-CM code is:", options: ["F10.23- (Alcohol dependence with withdrawal)", "F10.12- (Alcohol abuse with intoxication)", "F10.99 (Alcohol use, unspecified)", "Z72.89 (Other problems related to lifestyle)"], correctIndex: 0, rationale: "Alcohol dependence with withdrawal is coded to F10.23-, with additional characters specifying the type of withdrawal (uncomplicated, with delirium, with perceptual disturbance). Abuse and dependence codes should not be assigned together.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 5 Guidelines" },
  { id: "him-678", stem: "ICD-10-CM Chapter 6 guidelines state that pain codes from category G89 should NOT be assigned when:", options: ["A definitive diagnosis for the underlying cause of the pain has been established and the reason for the encounter is treatment of the underlying condition", "The pain is chronic", "The patient is in a pain management clinic", "The pain is post-procedural"], correctIndex: 0, rationale: "When the underlying cause of pain is known and the encounter is for treatment of that condition, codes from G89 are generally not needed. G89 codes are used when pain itself is the reason for the encounter or provides additional useful information.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 6 Guidelines" },
  { id: "him-679", stem: "A patient diagnosed with dominant side hemiplegia following a cerebral infarction that occurred 8 months ago is coded with:", options: ["I69.351 (Hemiplegia and hemiparesis following cerebral infarction affecting right dominant side)", "I63.- (Cerebral infarction) with the acute stroke code", "G81.91 (Hemiplegia, unspecified, affecting right dominant side)", "Only Z87.73 (Personal history of TIA and cerebral infarction)"], correctIndex: 0, rationale: "Deficits from cerebrovascular disease that persist beyond the acute phase are coded with category I69 (Sequelae of cerebrovascular disease) codes, which identify both the deficit and the type of stroke that caused it.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Chapter 6 Guidelines" },
  { id: "him-680", stem: "In ICD-10-CM Chapter 7 (Diseases of the Eye), laterality is indicated by:", options: ["The 4th, 5th, or 6th character designating right eye, left eye, bilateral, or unspecified", "A separate modifier code", "An external cause code", "The 7th character only"], correctIndex: 0, rationale: "ICD-10-CM eye codes incorporate laterality within the code structure itself, using specific characters to indicate right eye, left eye, bilateral involvement, or unspecified laterality.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Chapter 7 Guidelines" },
  { id: "him-681", stem: "Glaucoma codes in ICD-10-CM require identification of:", options: ["The type of glaucoma, laterality, and the glaucoma stage", "Only the type of glaucoma", "Only the laterality", "Only the intraocular pressure reading"], correctIndex: 0, rationale: "ICD-10-CM glaucoma codes (H40-H42) are combination codes requiring identification of the type (open-angle, angle-closure, etc.), laterality (right, left, bilateral), and the stage (mild, moderate, severe, indeterminate).", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 7 Guidelines" },
  { id: "him-682", stem: "When a patient has bilateral glaucoma with different stages in each eye, the coder should:", options: ["Assign separate codes for each eye rather than using the bilateral code", "Use only the bilateral code with the higher stage", "Code only the more severely affected eye", "Assign a single unspecified glaucoma code"], correctIndex: 0, rationale: "When bilateral glaucoma has different stages in each eye, a code for each eye (right and left) should be assigned with the appropriate stage rather than using the bilateral code, to accurately capture the differing severity.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Chapter 7 Guidelines" },
  { id: "him-683", stem: "ICD-10-CM Chapter 8 (Diseases of the Ear) codes include laterality for:", options: ["Most ear conditions, specifying right ear, left ear, bilateral, or unspecified", "Only hearing loss codes", "Only otitis media codes", "No ear conditions include laterality"], correctIndex: 0, rationale: "Chapter 8 ear codes incorporate laterality within the code structure for most conditions, allowing specification of right ear, left ear, bilateral, or unspecified to accurately describe the affected side.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Chapter 8 Guidelines" },
  { id: "him-684", stem: "Hypertensive heart disease (I11.-) is coded when:", options: ["A causal relationship between hypertension and heart disease is stated or implied by the documentation", "The patient has both hypertension and any heart condition without documentation of a link", "Only when the physician explicitly states 'hypertensive heart disease'", "The patient has an elevated blood pressure reading during one visit"], correctIndex: 0, rationale: "ICD-10-CM assumes a causal relationship between hypertension and heart disease when both are documented. The guideline states that heart conditions in I50.- or I51.4-I51.9 with hypertension are classified to I11.- (Hypertensive heart disease).", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 9 Guidelines" },
  { id: "him-685", stem: "The causal relationship between hypertension and chronic kidney disease (CKD) is:", options: ["Assumed in ICD-10-CM unless the physician documents a different cause for the CKD", "Never assumed and must always be explicitly documented", "Only assumed for CKD stages 4 and 5", "Only assumed in inpatient settings"], correctIndex: 0, rationale: "ICD-10-CM presumes a causal relationship between hypertension and CKD. When both are documented, codes from I12 (Hypertensive CKD) should be assigned along with the appropriate N18 code for the CKD stage.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 9 Guidelines" },
  { id: "him-686", stem: "A patient with hypertensive heart disease AND hypertensive CKD should be coded to:", options: ["Category I13 (Hypertensive heart and chronic kidney disease)", "Category I11 and I12 separately", "Only I11 (Hypertensive heart disease)", "Only I12 (Hypertensive chronic kidney disease)"], correctIndex: 0, rationale: "When a patient has both hypertensive heart disease and hypertensive CKD, the combination code from category I13 should be assigned, along with appropriate additional codes for heart failure (if applicable) and CKD stage.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 9 Guidelines" },
  { id: "him-687", stem: "For acute myocardial infarction (AMI) coding, an initial AMI that is still being treated is designated by:", options: ["A code from category I21 (ST elevation and non-ST elevation myocardial infarction)", "A code from I22 (Subsequent ST elevation and non-ST elevation myocardial infarction)", "I25.2 (Old myocardial infarction)", "Only the troponin level code"], correctIndex: 0, rationale: "Category I21 codes are used for the initial (first) acute myocardial infarction during the encounter when the patient is still receiving care for the AMI. I21 codes are used for the initial 4-week time frame.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 9 Guidelines" },
  { id: "him-688", stem: "Code I22 (Subsequent myocardial infarction) is used when:", options: ["A patient suffers a new AMI within 4 weeks (28 days) of an initial AMI", "The patient has a history of a prior AMI more than 4 weeks ago", "The patient is seen for follow-up of a healed AMI", "The initial AMI code needs to be corrected"], correctIndex: 0, rationale: "I22 codes are assigned when a new acute myocardial infarction occurs within 4 weeks (28 days) of an initial AMI coded with I21. A code from I21 must also be assigned in conjunction with I22.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Chapter 9 Guidelines" },
  { id: "him-689", stem: "Atherosclerotic heart disease of native coronary artery with angina pectoris is an example of:", options: ["A combination code (I25.11-) that classifies both conditions together", "Two separate codes required", "An excluded combination", "A code requiring an external cause"], correctIndex: 0, rationale: "ICD-10-CM provides combination codes (I25.11-) for atherosclerotic heart disease of native coronary artery with various types of angina pectoris, eliminating the need for separate codes for each condition.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Combination Codes" },
  { id: "him-690", stem: "According to Chapter 9 guidelines, the causal relationship between hypertension and heart failure:", options: ["Is assumed when both conditions are documented by the provider", "Must be explicitly stated in every encounter", "Only applies to systolic heart failure", "Is never assumed and always requires query"], correctIndex: 0, rationale: "ICD-10-CM guidelines presume a causal link between hypertension and heart conditions classified to I50 and I51.4-I51.9. The coder should assign I11.0 (Hypertensive heart disease with heart failure) when both are documented.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 9 Guidelines" },
  { id: "him-691", stem: "When coding acute respiratory failure with COPD exacerbation, the sequencing depends on:", options: ["The circumstances of the admission and the documentation of which condition prompted the encounter", "Always listing respiratory failure first", "Always listing COPD first", "Alphabetical order of the codes"], correctIndex: 0, rationale: "Either condition may be sequenced as the principal diagnosis depending on the circumstances of admission. The selection of the principal diagnosis should be based on which condition was the primary reason for admission.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 10 Guidelines" },
  { id: "him-692", stem: "COPD with acute exacerbation is coded using:", options: ["J44.1 (Chronic obstructive pulmonary disease with acute exacerbation)", "J44.0 (COPD with acute lower respiratory infection)", "J44.9 (COPD, unspecified)", "J43.9 (Emphysema, unspecified)"], correctIndex: 0, rationale: "J44.1 is the code for COPD with acute exacerbation. If the exacerbation is accompanied by a lower respiratory infection, J44.0 should be used instead, with an additional code for the specific infection.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 10 Guidelines" },
  { id: "him-693", stem: "Asthma codes in ICD-10-CM require identification of:", options: ["The type (mild intermittent, mild persistent, moderate persistent, severe persistent) and whether the encounter is for exacerbation or status asthmaticus", "Only whether the patient uses an inhaler", "Only the age of the patient", "Only the allergen trigger"], correctIndex: 0, rationale: "ICD-10-CM asthma codes (J45.-) are combination codes specifying severity level (mild intermittent, mild persistent, moderate persistent, severe persistent) and clinical status (uncomplicated, with exacerbation, or with status asthmaticus).", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 10 Guidelines" },
  { id: "him-694", stem: "An 'Includes' note in ICD-10-CM indicates:", options: ["The conditions listed are included under and further defined by the code category", "The conditions are excluded from the category", "The conditions require additional codes", "The conditions are only applicable in inpatient settings"], correctIndex: 0, rationale: "An Includes note at the beginning of a chapter, block, or category lists conditions that are included in that classification. These terms provide additional examples or conditions classified to that code.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-695", stem: "The instruction 'Code first' in ICD-10-CM means:", options: ["Another condition should be sequenced before this code when both are present", "This code should be listed first", "Only one code is needed", "The code is only used as a principal diagnosis"], correctIndex: 0, rationale: "A 'Code first' note indicates that the code cannot be used as a principal/first-listed diagnosis. The underlying condition listed in the 'Code first' instruction must be sequenced before the code with the note.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Sequencing Rules" },
  { id: "him-696", stem: "The instruction 'Use additional code' in ICD-10-CM indicates:", options: ["An additional code should be assigned to provide a more complete picture of the diagnosis", "The additional code replaces the primary code", "Only the additional code is required", "The code is optional and never required"], correctIndex: 0, rationale: "'Use additional code' instructs the coder that an additional code should be assigned to fully describe the condition. The code with the 'Use additional code' note is sequenced first, followed by the additional code.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Sequencing Rules" },
  { id: "him-697", stem: "The etiology/manifestation coding convention in ICD-10-CM requires:", options: ["The etiology (underlying condition) code to be sequenced first, followed by the manifestation code", "The manifestation code to be sequenced first", "Only one of the two codes to be assigned", "Both codes to be assigned in any order"], correctIndex: 0, rationale: "The etiology/manifestation convention requires coding the underlying disease (etiology) first, followed by the manifestation. Manifestation codes (often in italics or brackets) cannot be used as principal diagnoses.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Sequencing Rules" },
  { id: "him-698", stem: "In ICD-10-CM, NEC (Not Elsewhere Classifiable) means:", options: ["The classification does not have a more specific code for the documented condition", "The condition is not codeable", "The documentation is inadequate", "The condition does not exist"], correctIndex: 0, rationale: "NEC indicates that ICD-10-CM does not provide a specific code for the condition as documented. The condition is classified to an 'other specified' code. This is a system limitation, not a documentation issue.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-699", stem: "In ICD-10-CM, NOS (Not Otherwise Specified) means:", options: ["The documentation does not provide enough detail to assign a more specific code", "The condition has no code available", "The code is used only for research", "The classification system lacks the code"], correctIndex: 0, rationale: "NOS is the equivalent of 'unspecified' and indicates the physician's documentation does not provide sufficient detail to assign a more specific code. This is a documentation issue, not a system limitation.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-700", stem: "According to ICD-10-CM guidelines, when the same condition is described as both acute and chronic, the coder should:", options: ["Assign separate codes for both the acute and chronic condition if the classification provides distinct codes", "Code only the acute condition", "Code only the chronic condition", "Use an unspecified code"], correctIndex: 0, rationale: "When the same condition is described as both acute (subacute) and chronic, separate codes for each should be assigned if distinct codes exist, with the acute code sequenced first per alphabetic index instructions.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-701", stem: "A code from Chapter 1 for infectious organisms (B95-B97) is used as:", options: ["An additional code to identify the infectious agent when the primary infection code does not include the organism", "A principal diagnosis code", "A standalone code for all infections", "Only for hospital-acquired infections"], correctIndex: 0, rationale: "Codes B95-B97 are supplementary codes used as additional codes to identify the causative organism in diseases classified elsewhere. They are never used as principal/first-listed diagnoses.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 1 Guidelines" },
  { id: "him-702", stem: "When coding a patient with sepsis and a localized infection, the sequencing should be:", options: ["The sepsis code first (A40.-, A41.-), followed by the code for the localized infection", "The localized infection first", "Only the sepsis code", "Only the localized infection code"], correctIndex: 0, rationale: "When a patient has sepsis with a localized infection, the systemic infection code is sequenced first, followed by the code for the localized infection. If the localized infection led to the sepsis, both are coded with proper sequencing.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Sequencing Rules" },
  { id: "him-703", stem: "The ICD-10-CM code structure consists of:", options: ["3 to 7 alphanumeric characters with the first character always being alpha", "Exactly 5 numeric characters", "2 to 4 alpha characters", "Exactly 7 numeric characters only"], correctIndex: 0, rationale: "ICD-10-CM codes are 3 to 7 characters in length. The first character is always alphabetic (A-Z, excluding U). Characters 2-3 are numeric. Characters 4-7 may be alpha or numeric and provide greater specificity.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-704", stem: "A patient presents with pneumonia due to Streptococcus pneumoniae. The correct code is:", options: ["J13, Pneumonia due to Streptococcus pneumoniae", "J18.9, Pneumonia, unspecified organism", "J15.9, Unspecified bacterial pneumonia", "B95.3, Streptococcus pneumoniae as cause of diseases classified elsewhere"], correctIndex: 0, rationale: "J13 is the specific combination code for pneumonia due to Streptococcus pneumoniae. When a specific code exists for the organism causing pneumonia, that code should be assigned rather than an unspecified code.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 10 Guidelines" },
  { id: "him-705", stem: "When a patient has COPD with an acute lower respiratory infection, the coder assigns:", options: ["J44.0 (COPD with acute lower respiratory infection) and an additional code to identify the specific infection", "Only J44.0", "Only the infection code", "J44.1 (COPD with acute exacerbation)"], correctIndex: 0, rationale: "Per guidelines, J44.0 is assigned along with an additional code to identify the specific lower respiratory infection. J44.0 alone does not specify the type of infection, so the additional code provides necessary clinical detail.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 10 Guidelines" },
  { id: "him-706", stem: "Influenza with pneumonia in ICD-10-CM is coded using:", options: ["A combination code from category J09-J11 that identifies both influenza and pneumonia", "Separate codes for influenza and pneumonia", "Only the pneumonia code", "Only the influenza code"], correctIndex: 0, rationale: "ICD-10-CM provides combination codes for influenza with various manifestations including pneumonia. The appropriate influenza code (J09, J10, or J11 depending on virus type) with pneumonia subcategory is assigned.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 10 Guidelines" },
  { id: "him-707", stem: "In ICD-10-CM, Chapter 2 guidelines state that when treatment is directed at the malignancy:", options: ["The malignancy is designated as the principal diagnosis unless the encounter is specifically for chemotherapy, radiation, or immunotherapy administration", "The symptom is always the principal diagnosis", "The stage of cancer determines sequencing", "Metastatic sites are always sequenced first"], correctIndex: 0, rationale: "When treatment is directed at the malignancy, it is the principal diagnosis. Exceptions include encounters solely for chemotherapy (Z51.11), radiation therapy (Z51.0), or immunotherapy (Z51.12), where those codes are sequenced first.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 2 Guidelines" },
  { id: "him-708", stem: "A patient with metastatic bone cancer from a primary lung malignancy should be coded with:", options: ["C34.- (primary malignant neoplasm of lung) and C79.51 (secondary malignant neoplasm of bone)", "C79.51 only", "C34.- only", "C40.- (malignant neoplasm of bone, primary)"], correctIndex: 0, rationale: "When a patient has a known primary malignancy with metastasis, the primary site code and secondary (metastatic) site code are both assigned. The sequencing depends on the focus of treatment for that encounter.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 2 Guidelines" },
  { id: "him-709", stem: "When a primary malignant neoplasm has been previously excised and there is no current treatment directed to that site, but the patient has a current secondary (metastatic) neoplasm:", options: ["The secondary neoplasm is the principal diagnosis and a personal history code for the former primary site is assigned", "The primary site code is still used", "Only the secondary neoplasm is coded", "No neoplasm codes are assigned"], correctIndex: 0, rationale: "When the primary malignancy has been excised with no further treatment at that site, a personal history code (Z85.-) replaces the primary neoplasm code. The secondary (metastatic) site code becomes the principal diagnosis if treatment is directed there.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Chapter 2 Guidelines" },
  { id: "him-710", stem: "Diabetes mellitus codes in ICD-10-CM are classified based on:", options: ["The type of diabetes and the body system affected by the complication", "Only the blood glucose level", "Only the patient's age", "Only whether insulin is administered"], correctIndex: 0, rationale: "ICD-10-CM diabetes codes are combination codes identifying the type (Type 1, Type 2, drug-induced, etc.) and the body system complication (kidney, eye, neurological, circulatory, etc.) in a single code.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Chapter 4 Guidelines" },
  { id: "him-711", stem: "A patient with Type 1 diabetes on an insulin pump should be coded with:", options: ["E10.- code(s) for the diabetes type and complications plus Z96.41 (Presence of insulin pump)", "Only E11.- codes", "E10.- without any device code", "Z96.41 only"], correctIndex: 0, rationale: "Type 1 diabetes is coded with E10.- codes. When the patient uses an insulin pump, Z96.41 is assigned as an additional code. Code Z79.4 (long-term use of insulin) is not assigned for Type 1 patients as insulin is inherent.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 4 Guidelines" },
  { id: "him-712", stem: "Secondary diabetes mellitus due to pancreatectomy is coded under:", options: ["E89.1 (Postprocedural hypoinsulinemia) and E13.- (Other specified diabetes mellitus)", "E10.- (Type 1 diabetes mellitus)", "E11.- (Type 2 diabetes mellitus)", "E08.- (Diabetes mellitus due to underlying condition)"], correctIndex: 0, rationale: "Diabetes resulting from surgical removal of the pancreas is coded as postprocedural hypoinsulinemia (E89.1) with an additional code from E13.- for the specific type of diabetes and any complications.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Chapter 4 Guidelines" },
  { id: "him-713", stem: "The 'Code also' note in ICD-10-CM instructs the coder to:", options: ["Assign an additional code if both conditions are documented, with no specific sequencing requirement implied", "Always code the noted condition first", "Ignore the second condition", "Only code the first condition listed"], correctIndex: 0, rationale: "A 'Code also' note indicates that two codes may be needed, but unlike 'Code first' or 'Use additional code,' it does not specify sequencing. Either condition may be sequenced first depending on the encounter.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-714", stem: "When an outpatient encounter results in no definitive diagnosis, the coder should code:", options: ["Signs, symptoms, and abnormal findings that prompted the encounter", "A suspected or probable diagnosis", "Rule-out diagnoses", "The most severe possible condition"], correctIndex: 0, rationale: "Per outpatient coding guidelines, uncertain diagnoses (probable, suspected, rule out) are NOT coded. Instead, the signs, symptoms, and abnormal test findings that exist at the time of the encounter are coded.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-715", stem: "For inpatient encounters, conditions documented as 'probable,' 'suspected,' or 'likely' should be:", options: ["Coded as if the condition exists, per the Uniform Hospital Discharge Data Set guidelines", "Not coded until confirmed by laboratory results", "Coded with a Z code only", "Coded as signs and symptoms only"], correctIndex: 0, rationale: "Per inpatient coding guidelines, conditions qualified as probable, suspected, likely, or comparable terms should be coded as if the condition were established. This differs from outpatient guidelines.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-716", stem: "The principal diagnosis for an inpatient encounter is defined as:", options: ["The condition established after study to be chiefly responsible for occasioning the admission", "The most severe condition", "The first condition documented", "The condition requiring the most expensive treatment"], correctIndex: 0, rationale: "The principal diagnosis is defined as the condition established after study to be chiefly responsible for occasioning the admission of the patient to the hospital for care, per the Uniform Hospital Discharge Data Set (UHDDS).", difficulty: 1, category: "ICD-10-CM Coding", topic: "Sequencing Rules" },
  { id: "him-717", stem: "When two or more diagnoses equally meet the criteria for principal diagnosis, the coder should:", options: ["Select either condition as the principal diagnosis unless the Alphabetic Index, Tabular List, or coding guidelines provide sequencing direction", "Always select the one with the higher code number", "Always select the more serious condition", "Query the physician for every case"], correctIndex: 0, rationale: "When two or more diagnoses equally meet the definition of principal diagnosis, either may be sequenced first unless coding conventions or guidelines provide specific sequencing direction.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Sequencing Rules" },
  { id: "him-718", stem: "A patient admitted for a symptom with an underlying condition discovered during the stay should have:", options: ["The underlying condition sequenced as principal diagnosis if it is confirmed and the symptom is integral to it", "The symptom as principal diagnosis always", "Both coded with no specific sequencing rules", "Only the symptom coded"], correctIndex: 0, rationale: "When a patient is admitted for a symptom and the underlying cause is determined during the encounter, the underlying condition is sequenced as principal diagnosis if the symptom is routinely associated with (integral to) that condition.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Sequencing Rules" },
  { id: "him-719", stem: "ICD-10-CM Chapter 9 guidelines for acute cerebrovascular accidents state:", options: ["Codes from category I63 (Cerebral infarction) should be used during the acute phase, with additional codes for deficits that persist beyond the acute phase from I69", "Only symptom codes should be used", "Category I69 codes are used during the acute phase", "External cause codes are never required"], correctIndex: 0, rationale: "During the acute phase of a stroke, codes from I60-I63 are assigned. Category I69 (Sequelae of cerebrovascular disease) codes are used for persistent deficits after the acute phase. Both cannot be assigned simultaneously for the same event.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 9 Guidelines" },
  { id: "him-720", stem: "The 'with' convention in the ICD-10-CM Alphabetic Index means:", options: ["The word 'with' should be interpreted as 'associated with' or 'due to' when it appears in a code title, Alphabetic Index, or instructional note", "The conditions must occur simultaneously", "Both conditions must be on the same date of service", "The patient must have both conditions on a single claim"], correctIndex: 0, rationale: "The 'with' convention assumes a causal relationship between two conditions linked by 'with' in the Alphabetic Index or Tabular List. The provider's documentation must include both conditions, but a direct linkage statement is not required.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-721", stem: "When a patient has a malignant neoplasm of an ectopic tissue site, the code assignment should be:", options: ["To the site mentioned in the documentation (e.g., ectopic pancreatic tissue of the stomach is coded to malignant neoplasm of stomach)", "To the site of the normal tissue origin", "To an unspecified site", "To both the ectopic and normal tissue sites"], correctIndex: 0, rationale: "Malignant neoplasms of ectopic tissue are coded to the site of the ectopic tissue, not to the site where that tissue normally occurs. Documentation of the specific anatomical location guides code selection.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Chapter 2 Guidelines" },
  { id: "him-722", stem: "A patient with functional activity of a neoplasm requires:", options: ["A code for the neoplasm and an additional code from the appropriate endocrine chapter to identify the functional activity", "Only the neoplasm code", "Only the endocrine disorder code", "No additional codes beyond the neoplasm"], correctIndex: 0, rationale: "When neoplasms have functional activity (e.g., hormone production), the neoplasm code is assigned along with an additional code from Chapter 4 (Endocrine) to identify the functional activity, such as catecholamine overproduction in pheochromocytoma.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Chapter 2 Guidelines" },
  { id: "him-723", stem: "Coding of complications of insulin pump malfunction for Type 1 diabetes requires:", options: ["T85.6- for mechanical complication of the device, T38.3X6- for underdosing of insulin, and the appropriate E10 code for the diabetes with any complications", "Only the diabetes code", "Only the device malfunction code", "Only T38.3X6-"], correctIndex: 0, rationale: "Insulin pump malfunction resulting in underdosing requires multiple codes: the mechanical complication code (T85.6-), the underdosing code (T38.3X6-), and the diabetes code (E10.-) with appropriate complications.", difficulty: 5, category: "ICD-10-CM Coding", topic: "Chapter 4 Guidelines" },
  { id: "him-724", stem: "Chapter 5 ICD-10-CM guidelines state that for substance use disorders, the codes for abuse and dependence:", options: ["Should not be assigned together for the same substance", "Should always be assigned together", "Are interchangeable", "Require confirmation by a psychiatrist"], correctIndex: 0, rationale: "Per ICD-10-CM guidelines, abuse and dependence codes should not be assigned together for the same substance. If both are documented, only the dependence code is assigned as it represents the more severe condition.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 5 Guidelines" },
  { id: "him-725", stem: "Pain that is documented as postoperative (post-thoracotomy, post-procedural) without further specification is coded to:", options: ["The appropriate postprocedural pain code (G89.1-) rather than the code for the site of the pain", "Only the surgical procedure code", "Only the body site code", "T81.-, Complications of procedures NEC"], correctIndex: 0, rationale: "Post-procedural pain not specified as acute or chronic is assigned to G89.18 (Other acute postprocedural pain) or G89.28 (Other chronic postprocedural pain) depending on documentation, along with a code for the specific pain site if applicable.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 6 Guidelines" },
  { id: "him-726", stem: "Neoplasm-related pain documented by the provider is coded with:", options: ["G89.3 (Neoplasm related pain) which may be assigned as principal or first-listed when the reason for the encounter is pain management", "Only the neoplasm code", "R52 (Pain, unspecified)", "Only a Z code for palliative care"], correctIndex: 0, rationale: "G89.3 is assigned for pain documented as related to, associated with, or due to cancer. It can be the principal diagnosis when pain control/management is the reason for the encounter, with the neoplasm code as additional.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 6 Guidelines" },
  { id: "him-727", stem: "Dominant side involvement in hemiplegia coding defaults to:", options: ["The affected side is the dominant side when dominance is not documented, for ambidextrous patients, or when the right side is affected", "Always the left side", "Always non-dominant", "The side opposite to the documented weakness"], correctIndex: 0, rationale: "Per ICD-10-CM guidelines, when dominance is not documented, if the right side is affected the default is dominant, and if the left side is affected the default is non-dominant. For ambidextrous patients, the default is dominant.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 6 Guidelines" },
  { id: "him-728", stem: "For diabetic retinopathy coding in ICD-10-CM, the coder must also assign:", options: ["A code for the specific type of retinopathy (e.g., with or without macular edema) using the appropriate 4th and 5th characters", "Only the diabetes code", "A separate ophthalmology consultation code", "Only the visual acuity code"], correctIndex: 0, rationale: "ICD-10-CM diabetes codes for retinopathy are combination codes that include the type of diabetes, the type of retinopathy, and the presence or absence of macular edema, requiring selection of the most specific code available.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 7 Guidelines" },
  { id: "him-729", stem: "ICD-10-CM Chapter 9 acute MI codes have a time limitation of:", options: ["4 weeks (28 days) from the onset of the infarction", "30 days from onset", "6 weeks from onset", "90 days from onset"], correctIndex: 0, rationale: "ICD-10-CM considers an MI as acute for a period of 4 weeks (28 days). After this period, if there are no ongoing symptoms or treatment, the old MI code (I25.2) should be used instead.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 9 Guidelines" },
  { id: "him-730", stem: "When coding septic shock, the correct sequencing is:", options: ["The code for the underlying systemic infection first, R65.21 (Severe sepsis with septic shock), then codes for organ dysfunction", "R65.21 first", "Only the shock code R57.8", "T81.12 for postprocedural shock only"], correctIndex: 0, rationale: "Septic shock requires sequencing the underlying systemic infection first, followed by R65.21, then additional codes for specific organ dysfunction. Septic shock indicates severe sepsis, so R65.21 (not R65.20) is used.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Chapter 1 Guidelines" },
  { id: "him-731", stem: "When coding bacterial sepsis in a newborn, the coder should use:", options: ["A code from category P36 (Bacterial sepsis of newborn)", "A code from A41 (Other sepsis)", "B95-B96 codes only", "R65.2- (Severe sepsis)"], correctIndex: 0, rationale: "Bacterial sepsis of the newborn has its own specific category P36 in Chapter 16 (Perinatal conditions). The adult sepsis codes from A40-A41 are not used for neonatal bacterial sepsis.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 1 Guidelines" },
  { id: "him-732", stem: "Coding SIRS (Systemic Inflammatory Response Syndrome) of non-infectious origin requires:", options: ["The code for the underlying condition first, followed by R65.10 (SIRS of non-infectious origin without acute organ dysfunction) or R65.11 (with acute organ dysfunction)", "Only R65.10 or R65.11", "A41.9 (Sepsis, unspecified)", "Only the organ dysfunction code"], correctIndex: 0, rationale: "Non-infectious SIRS requires the underlying condition (e.g., trauma, burn) sequenced first, followed by R65.10 or R65.11 as appropriate. Additional codes for organ dysfunction are assigned when R65.11 is used.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Chapter 1 Guidelines" },
  { id: "him-733", stem: "Zika virus infection is classified in ICD-10-CM under:", options: ["A92.5, Zika virus disease", "B97.89, Other viral agents", "B34.9, Viral infection, unspecified", "A99, Unspecified viral hemorrhagic fever"], correctIndex: 0, rationale: "Zika virus disease has a specific ICD-10-CM code (A92.5) classified under Chapter 1 (Certain infectious and parasitic diseases) within the arthropod-borne viral fevers and viral hemorrhagic fevers block.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 1 Guidelines" },
  { id: "him-734", stem: "For a patient with carcinoma in situ of the cervix, the correct code category is:", options: ["D06, Carcinoma in situ of cervix uteri", "C53, Malignant neoplasm of cervix uteri", "N87, Dysplasia of cervix uteri", "Z12.4, Encounter for screening for malignant neoplasm of cervix"], correctIndex: 0, rationale: "Carcinoma in situ is classified separately from malignant neoplasms. D06 specifically identifies carcinoma in situ of the cervix uteri, indicating the neoplasm has not invaded surrounding tissue.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 2 Guidelines" },
  { id: "him-735", stem: "When coding a contiguous or overlapping malignant neoplasm that cannot be classified to a single subcategory:", options: ["A code for overlapping sites (subcategory .8) should be assigned", "Two separate codes for each site should be assigned", "Only the larger site is coded", "An unspecified site code is assigned"], correctIndex: 0, rationale: "When a malignant neoplasm overlaps two or more contiguous sites and the origin cannot be determined, the overlapping site code (subcategory .8) is assigned. If the origin is known, the code for that site is assigned.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Chapter 2 Guidelines" },
  { id: "him-736", stem: "Transplant complications in ICD-10-CM are coded from:", options: ["Category T86 (Complications of transplanted organs and tissue)", "Z94 (Transplanted organ and tissue status) only", "Only the infection code if present", "Z48.2 (Encounter for aftercare following organ transplant)"], correctIndex: 0, rationale: "Transplant complications are coded from T86.- with additional codes for the specific complication. Z94.- codes are status codes used to indicate the patient has had a transplant, not to report complications.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-737", stem: "The ICD-10-CM convention of 'See' in the Alphabetic Index indicates:", options: ["The coder must refer to another term to locate the correct code", "The code can be found at the current location", "The code is optional", "The condition is uncodeable"], correctIndex: 0, rationale: "A 'See' instruction following a main term in the Alphabetic Index directs the coder to another term under which the correct code can be found. It is a mandatory cross-reference.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-738", stem: "The 'See Also' convention in the Alphabetic Index means:", options: ["The coder should refer to another term if the initial entry does not provide all necessary information", "The coder must always look at the other term", "The code at the current location is incorrect", "The terms are identical"], correctIndex: 0, rationale: "'See Also' instructs the coder to refer to another term in the Alphabetic Index if all the information needed is not found under the first entry. Unlike 'See,' it is not mandatory if the original entry is sufficient.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-739", stem: "A patient with Type 2 diabetes mellitus with diabetic peripheral neuropathy is coded as:", options: ["E11.42 (Type 2 diabetes mellitus with diabetic polyneuropathy)", "E11.9 and G62.9", "G63 (Polyneuropathy in diseases classified elsewhere) only", "E11.40 (Type 2 DM with diabetic neuropathy, unspecified)"], correctIndex: 0, rationale: "E11.42 is the combination code for Type 2 diabetes with diabetic polyneuropathy (peripheral neuropathy). This single code captures both the diabetes type and the specific neurological complication.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 4 Guidelines" },
  { id: "him-740", stem: "Long-term (current) use of insulin in a Type 2 diabetic patient requires the additional code:", options: ["Z79.4 (Long-term (current) use of insulin)", "E10.- (Type 1 diabetes mellitus)", "Z79.84 (Long-term use of oral hypoglycemic drugs)", "No additional code is needed"], correctIndex: 0, rationale: "When a Type 2 diabetic patient uses insulin for blood glucose control, Z79.4 is assigned as an additional code. This code is not used for Type 1 diabetes because insulin use is inherent to that condition.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 4 Guidelines" },
  { id: "him-741", stem: "Thyrotoxicosis with thyroid storm requires the code:", options: ["E05.- with the 5th character '1' indicating thyroid storm/crisis", "E05.- with the 5th character '0' indicating without thyroid storm", "E06.- (Thyroiditis)", "E07.9 (Disorder of thyroid, unspecified)"], correctIndex: 0, rationale: "ICD-10-CM differentiates thyrotoxicosis with and without thyroid storm using the 5th character. A 5th character of '1' indicates with thyrotoxic crisis or storm, while '0' indicates without.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 4 Guidelines" },
  { id: "him-742", stem: "Malnutrition associated with a malignant neoplasm is coded by assigning:", options: ["The malignancy code first, followed by the appropriate malnutrition code", "Only the malnutrition code", "Only the malignancy code", "E46 (Unspecified protein-calorie malnutrition) only"], correctIndex: 0, rationale: "When malnutrition is associated with malignancy, the neoplasm code is typically sequenced first, followed by the specific malnutrition code (e.g., E43 for severe protein-calorie malnutrition, E44.- for moderate/mild).", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 4 Guidelines" },
  { id: "him-743", stem: "For coding dementia in diseases classified elsewhere, the ICD-10-CM convention requires:", options: ["The underlying physiological condition code first, followed by the manifestation code from F02.-", "F02.- as the principal diagnosis", "Only the dementia code", "Only the underlying condition code"], correctIndex: 0, rationale: "Dementia in diseases classified elsewhere (F02.-) follows the etiology/manifestation convention. The underlying condition (e.g., Alzheimer's G30.-, Parkinson's G20) is coded first, followed by F02.- as a manifestation code.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 5 Guidelines" },
  { id: "him-744", stem: "According to Chapter 6 guidelines, when the patient has chronic pain syndrome, the code assigned is:", options: ["G89.4 (Chronic pain syndrome) — this code is different from chronic pain (G89.29) and requires specific documentation", "G89.29 (Other chronic pain)", "R52 (Pain, unspecified)", "F45.41 (Pain disorder with related psychological factors)"], correctIndex: 0, rationale: "G89.4 (Chronic pain syndrome) is a distinct clinical entity different from generalized chronic pain. It requires specific documentation of 'chronic pain syndrome' and should not be confused with G89.29 (Other chronic pain).", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 6 Guidelines" },
  { id: "him-745", stem: "When coding epilepsy with intractable seizures, the term 'intractable' is equivalent to:", options: ["Pharmacoresistant, treatment resistant, refractory, and poorly controlled", "Well-controlled", "In remission", "Newly diagnosed"], correctIndex: 0, rationale: "In ICD-10-CM, the term intractable is used interchangeably with pharmacoresistant, treatment resistant, refractory, and poorly controlled epilepsy, all indicating seizures that do not respond adequately to treatment.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 6 Guidelines" },
  { id: "him-746", stem: "Chapter 7 guidelines for blindness coding state that if the visual impairment category is documented but the visual field is not:", options: ["Assign the appropriate code from H54.- based on the documented category of visual impairment", "Do not code the condition", "Assign only an unspecified eye disorder code", "Query the ophthalmologist before coding"], correctIndex: 0, rationale: "Visual impairment codes in H54.- are based on the category of impairment documented by the provider. Specific visual acuity values are not required for code assignment when the category is clearly documented.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 7 Guidelines" },
  { id: "him-747", stem: "Otitis media codes in ICD-10-CM Chapter 8 include:", options: ["Laterality, type (suppurative, nonsuppurative), and chronicity (acute, subacute, chronic)", "Only laterality", "Only the type of infection", "Only whether it is recurrent"], correctIndex: 0, rationale: "Otitis media codes in ICD-10-CM are combination codes capturing the type (suppurative, serous, mucoid), chronicity (acute, subacute, chronic), whether recurrent, and laterality within a single code.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 8 Guidelines" },
  { id: "him-748", stem: "Heart failure codes in ICD-10-CM differentiate between:", options: ["Systolic (HFrEF), diastolic (HFpEF), combined systolic and diastolic, and whether acute, chronic, or acute on chronic", "Only left-sided and right-sided", "Only mild and severe", "Only compensated and decompensated"], correctIndex: 0, rationale: "ICD-10-CM heart failure codes (I50.-) specify the type (systolic/HFrEF, diastolic/HFpEF, combined) and acuity (acute, chronic, acute on chronic), reflecting current clinical classification of heart failure.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 9 Guidelines" },
  { id: "him-749", stem: "When a patient with hypertension is admitted for surgery and the hypertension is incidental to the procedure, it is coded as:", options: ["A secondary diagnosis code, not as the principal diagnosis", "The principal diagnosis", "Not coded at all", "Using only Z code Z87.39"], correctIndex: 0, rationale: "When hypertension is not the reason for the encounter but is present and may affect treatment, it is coded as a secondary diagnosis. The principal diagnosis is the condition that prompted the surgery.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Chapter 9 Guidelines" },
  { id: "him-750", stem: "Ventilator-associated pneumonia is coded using:", options: ["J95.851 (Ventilator associated pneumonia) with an additional code to identify the organism", "Only J18.9 (Pneumonia, unspecified)", "Only the organism code", "J96.- (Respiratory failure) only"], correctIndex: 0, rationale: "Ventilator-associated pneumonia has a specific code J95.851, which should be assigned with an additional code to identify the causative organism. This is important for quality reporting and infection prevention.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 10 Guidelines" },
  { id: "him-751", stem: "When the provider documents 'acute exacerbation of chronic bronchitis,' the coder assigns:", options: ["J44.1 (Chronic obstructive pulmonary disease with acute exacerbation) when there is an underlying COPD component", "J20.- (Acute bronchitis) only", "J42 (Unspecified chronic bronchitis) only", "J21.- (Acute bronchiolitis)"], correctIndex: 0, rationale: "Acute exacerbation of chronic bronchitis with obstructive component is coded to J44.1. If the chronic bronchitis is not obstructive, the appropriate chronic bronchitis code with the acute exacerbation should be assigned.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 10 Guidelines" },
  { id: "him-752", stem: "Chapter 10 guidelines for status asthmaticus indicate:", options: ["Status asthmaticus is a life-threatening asthma exacerbation that does not respond to standard therapeutic measures and should not be coded with exacerbation together", "It is the same as mild intermittent asthma", "It does not require emergency treatment", "It is coded only in outpatient settings"], correctIndex: 0, rationale: "Status asthmaticus represents a severe, life-threatening asthma episode not responsive to therapeutic measures. An exacerbation code should not be assigned with status asthmaticus as status asthmaticus supersedes it in severity.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 10 Guidelines" },
  { id: "him-653b", stem: "What does the ICD-10-CM Tabular List provide that the Alphabetic Index does not?", options: ["Instructional notes such as Includes, Excludes1, Excludes2, Code first, and Use additional code", "Alphabetical listings of diseases", "Cross-reference terms", "Eponym listings"], correctIndex: 0, rationale: "The Tabular List is the alphanumerical list of codes organized by chapter, category, and subcategory. It contains instructional notes (Includes, Excludes1, Excludes2, Code first, Use additional code) not found in the Alphabetic Index.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-654b", stem: "Coding of adverse effects of drugs in ICD-10-CM requires:", options: ["The nature of the adverse effect coded first, followed by the appropriate code from T36-T50 with 5th or 6th character '5' for adverse effect", "Only the drug name", "Only the adverse effect code", "Only a Z code for drug therapy"], correctIndex: 0, rationale: "For adverse effects, the nature of the adverse effect (e.g., arrhythmia, GI bleeding) is coded first, followed by the appropriate adverse effect code from T36-T50 with the character indicating adverse effect in therapeutic use.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-655b", stem: "Underdosing of medications in ICD-10-CM is coded with:", options: ["Codes from T36-T50 with the 5th or 6th character '6' indicating underdosing, plus a code for the resulting condition", "Only the drug code", "Only the resulting condition", "Z91.1- (Patient's noncompliance with medical treatment) only"], correctIndex: 0, rationale: "Underdosing codes (character '6' from T36-T50) indicate the patient took less of a medication than prescribed. Additional codes for the condition resulting from underdosing and noncompliance codes (Z91.1-) may also be assigned.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-656b", stem: "External cause codes in ICD-10-CM serve the purpose of:", options: ["Capturing the cause of injury, the intent, the place of occurrence, the activity, and the patient's status", "Replacing diagnosis codes", "Serving as principal diagnoses", "Documenting treatment provided"], correctIndex: 0, rationale: "External cause codes provide data about the circumstances of injuries and health conditions, including mechanism of injury, intent (accidental, self-harm, assault), place of occurrence, activity, and the patient's status.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-657b", stem: "Place of occurrence codes in ICD-10-CM are found in category:", options: ["Y93 is activity, Y92 is place of occurrence, Y95 is nosocomial condition — the place of occurrence is Y92", "V00-V99", "W00-W19", "Y92 for place of occurrence"], correctIndex: 3, rationale: "Category Y92 codes identify the place of occurrence where an injury or event occurred (e.g., home, school, sports area, street). These are assigned once at the initial encounter only.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-658b", stem: "Activity codes in ICD-10-CM (Y93.-) describe:", options: ["The activity the patient was engaged in at the time the injury or condition occurred", "The treatment activity performed by the physician", "The patient's employment status", "The rehabilitation activity prescribed"], correctIndex: 0, rationale: "Category Y93 codes identify the activity the patient was engaged in at the time of the injury (e.g., running, swimming, cooking). These are used once at the initial encounter along with external cause codes.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-659b", stem: "Child and adult abuse coding in ICD-10-CM Chapter 19 requires:", options: ["A code for the confirmed abuse (T74.-) or suspected abuse (T76.-), with additional codes for the specific injuries and a perpetrator code if known", "Only the injury code", "Only the perpetrator code", "Only a Z code for counseling"], correctIndex: 0, rationale: "Confirmed abuse uses T74.- codes while suspected abuse uses T76.- codes. Additional codes identify specific injuries, the external cause, the perpetrator (Y07.-), and any associated mental health conditions.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-660b", stem: "ICD-10-CM fracture codes for traumatic injuries require a 7th character to indicate:", options: ["The encounter type (initial, subsequent) and for certain bones, the type of fracture (open/closed) and healing status (routine, delayed, nonunion, malunion)", "Only the body side", "Only the mechanism of injury", "Only the patient's age"], correctIndex: 0, rationale: "Fracture 7th characters provide extensive detail: A/B/C for initial encounter by fracture type, D/G/K for subsequent encounter with healing status, and S for sequela. The characters capture open/closed status and healing complications.", difficulty: 3, category: "ICD-10-CM Coding", topic: "7th Character Extensions" },
  { id: "him-661b", stem: "When a fracture is not documented as open or closed in ICD-10-CM, the default is:", options: ["Closed fracture", "Open fracture", "Unspecified fracture", "Pathological fracture"], correctIndex: 0, rationale: "Per ICD-10-CM guidelines, if a fracture is not indicated as open or closed, it should be coded as closed. This default applies to traumatic fractures when the documentation does not specify the type.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-662b", stem: "Pressure ulcer codes in ICD-10-CM require identification of:", options: ["The anatomical site, laterality, and the stage (1 through 4, unstageable, or unspecified)", "Only the anatomical site", "Only the stage", "Only whether it is healing or not"], correctIndex: 0, rationale: "ICD-10-CM pressure ulcer codes (L89.-) are combination codes requiring the specific anatomical site, laterality where applicable, and the stage. If a patient has pressure ulcers at multiple sites, each is coded separately.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-663b", stem: "When a pressure ulcer evolves from one stage to a higher stage during an encounter:", options: ["Only the code for the highest stage documented is assigned", "Codes for all stages are assigned", "Only the initial stage code is assigned", "An unspecified stage code is used"], correctIndex: 0, rationale: "Per ICD-10-CM guidelines, when a pressure ulcer progresses to a higher stage during the encounter, only the code for the highest stage reported is assigned. Multiple stage codes for the same ulcer are not necessary.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-664b", stem: "Chronic kidney disease (CKD) stages are coded using category:", options: ["N18 (Chronic kidney disease) with subcategories for stages 1-5 and end-stage renal disease", "N17 (Acute kidney failure)", "Z99.2 (Dependence on renal dialysis)", "N19 (Unspecified kidney failure)"], correctIndex: 0, rationale: "Category N18 classifies CKD by stage: N18.1 (Stage 1), N18.2 (Stage 2), N18.3 (Stage 3), N18.4 (Stage 4), N18.5 (Stage 5), and N18.6 (End-stage renal disease). The stage is determined by GFR values.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-665b", stem: "A patient with CKD on chronic dialysis should be coded with:", options: ["N18.- (stage code), Z99.2 (Dependence on renal dialysis), and Z91.15 if noncompliant with dialysis", "Only Z99.2", "Only N18.-", "N17.- (Acute kidney failure)"], correctIndex: 0, rationale: "Patients with CKD on dialysis require the N18 stage code plus Z99.2 (Dependence on renal dialysis) to fully describe the clinical status. If the patient is noncompliant, Z91.15 is also assigned.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-666b", stem: "BMI codes (Z68.-) in ICD-10-CM should be assigned:", options: ["As secondary codes only, based on documentation from any qualified healthcare professional, not just the attending physician", "As principal diagnosis codes", "Only when documented by the attending physician", "Only for pediatric patients"], correctIndex: 0, rationale: "BMI codes are secondary codes that may be based on documentation from any qualified healthcare professional (e.g., dietitian, nurse). However, the associated diagnosis (e.g., obesity) must be documented by the attending provider.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-667b", stem: "The ICD-10-CM convention of brackets [ ] in the Tabular List indicates:", options: ["Synonyms, alternative wording, or explanatory phrases", "Mandatory additional codes", "Optional code assignment", "Codes that should never be used"], correctIndex: 0, rationale: "In the ICD-10-CM Tabular List, brackets enclose synonyms, alternative wordings, or explanatory phrases that provide additional clarification for the code description but do not change the code meaning.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-668b", stem: "Parentheses ( ) in ICD-10-CM enclose:", options: ["Supplementary words (nonessential modifiers) that may be present or absent without affecting the code", "Required terms for code assignment", "Excluded conditions", "Sequencing instructions"], correctIndex: 0, rationale: "Parentheses enclose nonessential modifiers — supplementary words that may or may not be present in the diagnostic statement without affecting the code assignment. They provide additional context but are not required.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-669b", stem: "The colon (:) in ICD-10-CM Tabular List entries indicates:", options: ["An incomplete term that requires one or more of the modifiers that follow to make it assignable to a given category", "The end of a code description", "An optional modifier", "A cross-reference to another code"], correctIndex: 0, rationale: "The colon is used in the Tabular List after an incomplete term that needs one or more of the qualifying terms listed below it to be properly classified under that particular code or category.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-670b", stem: "When a patient has a postoperative complication that is not inherent to the procedure, it is coded to:", options: ["The appropriate complication code from Chapter 19 (T80-T88) or the body-system specific complication code, plus an additional code for the specific complication", "Only the procedure code", "Only the original diagnosis code", "A Z code for surgical aftercare"], correctIndex: 0, rationale: "Postoperative complications not inherent to the procedure are coded with appropriate complication codes from T80-T88 or body-system chapters (e.g., K91.-, J95.-, N99.-), plus additional codes for the specific complication.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-671b", stem: "Intraoperative complications are differentiated from postprocedural complications by:", options: ["Separate subcategories within each body system chapter, with specific codes for intraoperative vs. postprocedural disorders", "There is no differentiation in ICD-10-CM", "Only the 7th character", "Only external cause codes"], correctIndex: 0, rationale: "ICD-10-CM provides separate subcategories for intraoperative and postprocedural complications within each body system chapter (e.g., E36 for intraoperative endocrine complications vs. E89 for postprocedural endocrine complications).", difficulty: 4, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-672b", stem: "When coding pregnancy, childbirth, and the puerperium (Chapter 15), the trimester is indicated by:", options: ["The final character of the code (1=first trimester, 2=second trimester, 3=third trimester)", "A separate modifier code", "An external cause code", "The place of service code"], correctIndex: 0, rationale: "ICD-10-CM Chapter 15 codes incorporate trimester as the final character: 1=first trimester (less than 14 weeks), 2=second trimester (14-27 weeks), 3=third trimester (28 weeks to delivery).", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-673b", stem: "Chapter 15 codes are used only on:", options: ["The maternal record, never on the newborn record", "Both maternal and newborn records", "Only the newborn record", "The father's record"], correctIndex: 0, rationale: "ICD-10-CM Chapter 15 (Pregnancy, Childbirth, and the Puerperium) codes are used exclusively on the maternal record. The newborn's record uses Chapter 16 codes for conditions originating in the perinatal period.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-674b", stem: "For a normal delivery (O80), the conditions that must be met include:", options: ["Full-term, single, healthy liveborn infant delivered vaginally with no antepartum or postpartum complications, cephalic presentation, and no instrumentation", "Any vaginal delivery", "Any delivery of a live infant", "C-section with no complications"], correctIndex: 0, rationale: "Code O80 (Encounter for full-term uncomplicated delivery) requires a single liveborn, full-term, cephalic presentation, vaginal delivery without instrumentation, and no antepartum, intrapartum, or postpartum complications.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-675b", stem: "Z codes for outcome of delivery (Z37.-) are used:", options: ["As additional codes on the maternal record only, to indicate the outcome of delivery", "As principal diagnosis codes", "On the newborn record", "Only for stillbirths"], correctIndex: 0, rationale: "Z37.- codes indicate the outcome of delivery (single live birth, twins, etc.) and are always additional codes assigned on the maternal record only. They should be included on every maternal delivery record.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-676b", stem: "Chapter 16 (Certain Conditions Originating in the Perinatal Period) codes may be used:", options: ["Throughout the life of the patient if the condition originated in the perinatal period, regardless of current age", "Only during the first 28 days of life", "Only during the birth hospitalization", "Only during the first year of life"], correctIndex: 0, rationale: "Although Chapter 16 codes are for conditions originating in the perinatal period (before birth through the 28th day of life), they may be used throughout the patient's life if the condition is still present.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-677b", stem: "The principal diagnosis for a newborn birth record is:", options: ["A code from category Z38 (Liveborn infants according to place of birth and type of delivery)", "The delivery method code", "The mother's diagnosis", "The birth weight code"], correctIndex: 0, rationale: "A code from Z38 is always the principal diagnosis on the newborn birth record. It identifies the type of birth (single/multiple), place of birth (hospital/outside), and delivery method (vaginal/cesarean).", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-678b", stem: "Congenital anomaly codes from Chapter 17 (Q00-Q99) may be assigned:", options: ["As principal or additional diagnosis on any record regardless of age when the anomaly is still present", "Only on neonatal records", "Only through age 5", "Only at the time of initial diagnosis"], correctIndex: 0, rationale: "Congenital anomaly codes may be used throughout a patient's lifetime if the condition persists. They can be principal or additional diagnoses and are not limited to any specific age group.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-679b", stem: "Signs and symptoms codes from Chapter 18 (R00-R99) should be assigned when:", options: ["No definitive diagnosis has been established, or when the sign/symptom is not integral to the confirmed diagnosis", "A definitive diagnosis has been established and the symptom is inherent", "In every patient encounter regardless of diagnosis", "Only for emergency department visits"], correctIndex: 0, rationale: "Chapter 18 codes for signs and symptoms are assigned when no definitive diagnosis is established, or when a sign/symptom is not routinely associated with the established diagnosis and provides additional clinical information.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-680b", stem: "Z codes in ICD-10-CM (Chapter 21) represent:", options: ["Reasons for encounters when a person may not currently be sick, or when circumstances other than disease or injury prompt the encounter", "Only vaccination encounters", "Only newborn screening encounters", "Codes for deceased patients only"], correctIndex: 0, rationale: "Z codes capture reasons for encounters beyond active disease: screening, immunization, personal/family history, status codes, aftercare, counseling, and other factors influencing health status.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-681b", stem: "Which Z codes can be used as principal/first-listed diagnosis?", options: ["Certain Z codes may be principal diagnosis when the reason for the encounter is not a disease or injury (e.g., Z51.11 for chemotherapy, Z38.- for newborn)", "No Z codes can ever be principal", "All Z codes can be principal", "Only Z00-Z13 screening codes"], correctIndex: 0, rationale: "Certain Z codes may serve as principal/first-listed diagnoses when the encounter reason is not disease/injury. Examples include chemotherapy encounters (Z51.11), newborn births (Z38.-), and organ donor encounters (Z52.-).", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-682b", stem: "Status Z codes (Z93-Z99) indicate:", options: ["That the patient has a condition or device that is ongoing and affects care, such as transplant status, prosthetic device presence, or dependence on machines", "Only pregnancy status", "Only vaccination history", "Temporary conditions only"], correctIndex: 0, rationale: "Status Z codes indicate a patient's ongoing state that affects care: colostomy status (Z93.-), transplanted organ status (Z94.-), prosthetic device presence (Z96.-), or dependence on enabling machines (Z99.-).", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-683b", stem: "For coding purposes, an encounter for aftercare is coded with:", options: ["Z codes for aftercare (Z43-Z49, Z51) when the original condition has been treated and the patient is receiving follow-up care such as drain removal or medication adjustment", "The original condition code", "An injury code with 7th character 'D'", "A complication code"], correctIndex: 0, rationale: "Aftercare Z codes are used when the initial treatment is complete and the patient returns for follow-up care. For injuries and fractures, the acute injury code with 7th character 'D' for subsequent encounter is used instead.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-684b", stem: "ICD-10-CM laterality convention requires:", options: ["Coding to the specific side (right, left, bilateral) when laterality is a component of the code, defaulting to unspecified only when not documented", "Always coding bilateral", "Never coding laterality", "Coding only right side"], correctIndex: 0, rationale: "ICD-10-CM codes incorporate laterality when clinically significant. The coder should assign the code specifying the affected side (right, left, bilateral). Unspecified laterality codes should only be used when the side is not documented.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-685b", stem: "The ICD-10-CM guideline for coding of syndromes states:", options: ["Follow the Alphabetic Index guidance; if a syndrome has a specific code, assign it. If not, code the individual conditions that make up the syndrome", "Syndromes are never coded", "Always use an unspecified code", "Only code the most prominent feature"], correctIndex: 0, rationale: "When a syndrome has a specific ICD-10-CM code listed in the Alphabetic Index, that code is assigned. If no specific code exists, the coder should assign codes for each documented manifestation of the syndrome.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-686b", stem: "Coding of multiple injuries during the same encounter follows which guideline?", options: ["Assign separate codes for each injury, sequencing the most severe injury as the principal diagnosis unless the circumstances of the admission govern selection", "Assign only one injury code", "Always code the first injury documented", "Use only an unspecified injury code"], correctIndex: 0, rationale: "Each injury is coded separately with the most severe injury typically sequenced as principal diagnosis, unless coding guidelines or the circumstances of admission dictate otherwise.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-687b", stem: "When a patient has a pathological fracture due to osteoporosis, the code assignment should reflect:", options: ["A code from M80.- (Osteoporosis with current pathological fracture) which is a combination code including both the osteoporosis and fracture site", "Separate codes for osteoporosis and fracture", "Only the fracture code from S category", "Only M81.- (Osteoporosis without pathological fracture)"], correctIndex: 0, rationale: "Category M80 provides combination codes for osteoporosis with current pathological fracture, capturing both the underlying disease and the fracture site. Traumatic fracture codes from Chapter 19 should not be used for pathological fractures.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-688b", stem: "When coding burns in ICD-10-CM, the coder must identify:", options: ["The depth (first, second, third degree), the extent (percentage of body surface), the site, and the external cause", "Only the body site", "Only the degree of burn", "Only the external cause"], correctIndex: 0, rationale: "Burn coding requires depth (1st, 2nd, 3rd degree), anatomical site, total body surface area percentage (T31-T32), and external cause. The most severe burn is sequenced first when multiple burns exist.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-689b", stem: "Coding of poisoning in ICD-10-CM uses codes from:", options: ["T36-T65 with the 5th or 6th character indicating intent (accidental, intentional self-harm, assault, undetermined)", "Only external cause codes", "Only the substance code", "Only the manifestation of the poisoning"], correctIndex: 0, rationale: "Poisoning codes from T36-T65 combine the substance and the intent (accidental, intentional self-harm, assault, undetermined). The manifestation/nature of the poisoning is coded first, followed by the poisoning code.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-690b", stem: "When a patient is seen for complications of care, the complication code is sequenced:", options: ["As the principal or first-listed diagnosis when the encounter is specifically for treatment of the complication", "Always as a secondary diagnosis", "Only when the original procedure was done at the same facility", "Never as a principal diagnosis"], correctIndex: 0, rationale: "When the reason for the encounter is treatment of a complication of previous medical/surgical care, the complication code is sequenced as the principal diagnosis. The original condition may be coded as additional.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Sequencing Rules" },
  { id: "him-691b", stem: "ICD-10-CM coding for COVID-19 uses code:", options: ["U07.1 (COVID-19) as the principal diagnosis when the encounter is for COVID-19, with additional codes for associated manifestations", "Only B97.29 (Other coronavirus)", "Only J12.89 (Other viral pneumonia)", "Z20.822 (Contact with COVID-19) for confirmed cases"], correctIndex: 0, rationale: "U07.1 is used for confirmed COVID-19 diagnoses. It is sequenced as principal diagnosis when COVID-19 is the reason for the encounter. Additional codes describe manifestations such as pneumonia, respiratory failure, and other organ involvement.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-692b", stem: "Social determinants of health (SDOH) codes in ICD-10-CM are found in:", options: ["Categories Z55-Z65 (Persons with potential health hazards related to socioeconomic and psychosocial circumstances)", "Chapter 1 infectious disease codes", "Chapter 5 mental health codes", "Z80-Z84 family history codes"], correctIndex: 0, rationale: "SDOH Z codes (Z55-Z65) capture factors affecting health such as education/literacy problems (Z55), employment issues (Z56), housing problems (Z59), and social environment problems (Z60), supporting population health initiatives.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-693b", stem: "Coding of drug-resistant infections requires:", options: ["A code for the infection and an additional code from Z16 (Resistance to antimicrobial drugs) to identify drug resistance", "Only the infection code", "Only the Z16 resistance code", "A V code from an older classification"], correctIndex: 0, rationale: "Drug resistance is captured by assigning the infection code first, followed by the appropriate Z16 code to identify the specific drug resistance (e.g., Z16.11 for resistance to penicillins, Z16.12 for extended spectrum beta-lactamase resistance).", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 1 Guidelines" },
  { id: "him-694b", stem: "When a patient has both acute kidney failure and chronic kidney disease, the coder should:", options: ["Assign both the acute kidney failure code (N17.-) and the chronic kidney disease code (N18.-)", "Assign only the acute code", "Assign only the chronic code", "Assign N19 (Unspecified kidney failure)"], correctIndex: 0, rationale: "Both the acute and chronic kidney failure codes are assigned when both are documented. The sequencing depends on the reason for the encounter and which condition required the most treatment resources.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-695b", stem: "Coding of mechanical ventilation duration uses:", options: ["5A1935Z for less than 24 consecutive hours, 5A1945Z for 24-96 consecutive hours, and 5A1955Z for greater than 96 consecutive hours using ICD-10-PCS procedure codes", "Only an ICD-10-CM diagnosis code", "Only a CPT code", "No specific code exists for ventilator duration"], correctIndex: 0, rationale: "Mechanical ventilation duration is captured with ICD-10-PCS codes based on consecutive hours: less than 24 hours, 24-96 hours, and greater than 96 hours. The count begins from initiation in the current facility.", difficulty: 4, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-696b", stem: "ICD-10-CM laterality defaults when documentation does not specify side:", options: ["Assign the unspecified laterality code and query the provider when possible", "Always assign the right side", "Always assign bilateral", "Do not assign the code"], correctIndex: 0, rationale: "When the side is not documented and cannot be determined from the medical record, the unspecified laterality code is assigned. Best practice is to query the provider for clarification when feasible.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-697b", stem: "For a patient presenting with chest pain who is found to have an acute ST elevation myocardial infarction, the principal diagnosis is:", options: ["The acute STEMI code (I21.-) because the underlying cause was determined during the encounter", "R07.9 (Chest pain, unspecified)", "I25.10 (Atherosclerotic heart disease)", "Z03.89 (Observation for suspected condition ruled out)"], correctIndex: 0, rationale: "When a symptom leads to discovery of an underlying condition during the encounter, the underlying condition (STEMI) is coded as principal diagnosis because the chest pain is integral to (a symptom of) the MI.", difficulty: 2, category: "ICD-10-CM Coding", topic: "Sequencing Rules" },
  { id: "him-698b", stem: "Coding of a patient admitted for observation following a motor vehicle accident who is found to have no injuries:", options: ["Z04.1 (Encounter for examination and observation following transport accident) with an external cause code", "Only the external cause code", "Only Z03.89", "S codes for the suspected injuries"], correctIndex: 0, rationale: "When a patient is admitted for observation after an accident and no injuries are found, the appropriate observation Z code is assigned as principal diagnosis, along with external cause codes describing the accident circumstances.", difficulty: 3, category: "ICD-10-CM Coding", topic: "Coding Guidelines" },
  { id: "him-699b", stem: "The ICD-10-CM Alphabetic Index is organized as:", options: ["An index of diseases and injuries, an external cause of injuries index, a table of neoplasms, and a table of drugs and chemicals", "A numerical listing of all codes", "Only a disease listing by body system", "Only an alphabetical list of procedures"], correctIndex: 0, rationale: "The ICD-10-CM Alphabetic Index has four sections: the Index to Diseases and Injuries, the Table of Neoplasms, the Table of Drugs and Chemicals, and the Index to External Causes of Injuries.", difficulty: 1, category: "ICD-10-CM Coding", topic: "Coding Conventions" },
  { id: "him-700b", stem: "When coding a patient with both heart failure and hypertension, the ICD-10-CM guideline directs:", options: ["A causal relationship is assumed; assign I11.0 (Hypertensive heart disease with heart failure) plus an I50 code to specify the type of heart failure", "Assign I10 and I50 separately with no assumed relationship", "Assign only the heart failure code", "Query the physician before coding any relationship"], correctIndex: 0, rationale: "ICD-10-CM presumes a causal relationship between hypertension and heart failure. I11.0 is assigned along with an additional code from I50.- to identify the specific type of heart failure (systolic, diastolic, combined).", difficulty: 3, category: "ICD-10-CM Coding", topic: "Chapter 9 Guidelines" },
];
